insert into stores (id, slug, name, tagline, description, logo_text, address, hours, whatsapp, categories, theme, theme_dark, translations) values
  ('lamset-jamal', 'lamset-jamal', 'لمسة جمال', 'جمالك يبدأ من لمسة', 'متجر لمسة جمال متخصص بمنتجات المكياج والعناية بالبشرة الأصلية، مختارة بعناية لتمنحك إطلالة واثقة يومياً.', 'لمسة جمال', 'الشارع الرئيسي - دخلة الصحة القديمة', 'يومياً: 9:00ص - 11:00م', '970599111222', '{"الكل","مكياج","عناية بالبشرة","عطور","أدوات تجميل"}', '{"primary":"#16342b","primaryDark":"#0d2119","secondary":"#DDEEE2","surface":"#F6FAF7","ink":"#12201A","accent":"#735c00"}'::jsonb, '{"primary":"#5aa885","primaryDark":"#3c7a5c","secondary":"#DDEEE2","surface":"#1c1e17","ink":"#e8e4d7","accent":"#d3c087"}'::jsonb, '{"en":{"name":"Lamset Jamal","logoText":"Lamset Jamal","tagline":"Your beauty begins with a touch","description":"Lamset Jamal is a specialized store for authentic makeup and skincare products, carefully selected to give you a confident look every day.","address":"Nablus - Rafidia Street - Al-Amal Building, 1st Floor","hours":"Daily: 9:00 AM - 11:00 PM"},"he":{"name":"למסת ג''מאל","logoText":"למסת ג''מאל","tagline":"היופי שלך מתחיל במגע","description":"למסת ג''מאל היא חנות המתמחה במוצרי איפור וטיפוח עור מקוריים, שנבחרו בקפידה כדי להעניק לך מראה בטוח בכל יום.","address":"שכם - רחוב רפידיה - בניין אל-אמל, קומה 1","hours":"כל יום: 09:00-23:00"}}'::jsonb),
  ('lamset-sabaya', 'lamset-sabaya', 'لمسة صبايا', 'ستايلك، حكاية بتحكيها', 'متجر لمسة صبايا لعشاق الموضة والإكسسوارات العصرية، تشكيلة متجددة تناسب كل الأذواق والمناسبات.', 'لمسة صبايا', 'الشارع الرئيسي - دخلة الصحة القديمة', 'يومياً: 9:00ص - 11:00م', '970599333444', '{"الكل","إكسسوارات","حقائب","مجوهرات","ملابس"}', '{"primary":"#8E5FA6","primaryDark":"#5F3B75","secondary":"#F1E6F7","surface":"#FBF7FD","ink":"#241A2B","accent":"#E6A23C"}'::jsonb, '{"primary":"#b891ce","primaryDark":"#8a5fa8","secondary":"#F1E6F7","surface":"#1c1e17","ink":"#e8e4d7","accent":"#f0b35c"}'::jsonb, '{"en":{"name":"Lamset Sabaya","logoText":"Lamset Sabaya","tagline":"Your style, a story you tell","description":"Lamset Sabaya is a store for fashion and modern accessory lovers, with a constantly refreshed collection suited to every taste and occasion.","address":"Nablus - Main Roundabout - Al-Nakheel Commercial Complex","hours":"Daily: 9:00 AM - 11:00 PM"},"he":{"name":"למסת סבאיא","logoText":"למסת סבאיא","tagline":"הסטייל שלך, סיפור שאת מספרת","description":"למסת סבאיא היא חנות לאוהבות אופנה ואביזרים עדכניים, עם קולקציה מתחדשת המתאימה לכל טעם ואירוע.","address":"שכם - הכיכר הראשית - מתחם אל-נח''יל המסחרי","hours":"כל יום: 09:00-23:00"}}'::jsonb),
  ('maaraz-lamset-jamal', 'maaraz-lamset-jamal', 'معرض لمسة جمال', 'هدايا وتفاصيل تلمس القلب', 'معرض لمسة جمال وجهتك للهدايا الفاخرة والعطور والديكور المنزلي الراقي لكل المناسبات.', 'معرض لمسة جمال', 'الشارع الرئيسي - دخلة الصحة القديمة', 'يومياً: 9:00ص - 11:00م', '970599555666', '{"الكل","عطور","هدايا","ديكور","شموع"}', '{"primary":"#1C1C1E","primaryDark":"#000000","secondary":"#EFE6D8","surface":"#FAF7F0","ink":"#1C1C1E","accent":"#C9A66B"}'::jsonb, '{"primary":"#cfa96e","primaryDark":"#a3814f","secondary":"#EFE6D8","surface":"#1c1e17","ink":"#e8e4d7","accent":"#e0c48f"}'::jsonb, '{"en":{"name":"Maaraz Lamset Jamal","logoText":"Maaraz Lamset Jamal","tagline":"Gifts and details that touch the heart","description":"Maaraz Lamset Jamal is your destination for luxury gifts, perfumes and elegant home decor for every occasion.","address":"Nablus - Old University Street - Next to Bank of Palestine","hours":"Daily: 9:00 AM - 11:00 PM"},"he":{"name":"מעראז'' למסת ג''מאל","logoText":"מעראז'' למסת ג''מאל","tagline":"מתנות ופרטים שנוגעים בלב","description":"מעראז'' למסת ג''מאל היא היעד שלך למתנות יוקרה, בשמים ועיצוב בית אלגנטי לכל אירוע.","address":"שכם - רחוב האוניברסיטה הישנה - ליד בנק פלסטין","hours":"כל יום: 09:00-23:00"}}'::jsonb)
insert into products (id, store_id, name, category, price, old_price, image, images, description, colors, sizes, translations) values
  ('lj-001', 'lamset-jamal', 'روج مطفي - Velvet Red', 'مكياج', 45, 55, 'https://picsum.photos/seed/lj001/600/700', '{"https://picsum.photos/seed/lj001/600/700","https://picsum.photos/seed/lj001b/600/700"}', 'روج مطفي بتركيبة كريمية غنية بتدوم طول اليوم بدون ما يجفف الشفايف.', '{"#A6455C","#7C2E40","#C9A66B"}', '{}', '{"en":{"name":"Velvet Red Matte Lipstick","description":"A rich, creamy matte lipstick that lasts all day without drying your lips."},"he":{"name":"שפתון מאט אדום קטיפה","description":"שפתון מאט בטקסטורה קרמית עשירה שמחזיק כל היום בלי לייבש את השפתיים."}}'::jsonb),
