  ('lj-003', 'lamset-jamal', 'سيروم فيتامين C', 'عناية بالبشرة', 80, 95, 'https://picsum.photos/seed/lj003/600/700', '{"https://picsum.photos/seed/lj003/600/700"}', 'سيروم مضاد للأكسدة بيفتح البشرة ويقلل التصبغات مع الاستخدام اليومي.', '{}', '{}', '{"en":{"name":"Vitamin C Serum","description":"An antioxidant serum that brightens skin and reduces pigmentation with daily use."},"he":{"name":"סרום ויטמין C","description":"סרום אנטי-אוקסידנטי שמבהיר את העור ומפחית כתמי גוון בשימוש יומי."}}'::jsonb),
  ('lj-004', 'lamset-jamal', 'عطر Amber Bloom', 'عطور', 120, NULL, 'https://picsum.photos/seed/lj004/600/700', '{"https://picsum.photos/seed/lj004/600/700"}', 'عطر شرقي دافئ بمزيج من العنبر والفانيليا، ثبات طويل يدوم لساعات.', '{}', '{"30ml","50ml","100ml"}', '{"en":{"name":"Amber Bloom Perfume","description":"A warm oriental fragrance blending amber and vanilla, with long-lasting hours of wear."},"he":{"name":"בושם Amber Bloom","description":"בושם מזרחי חם המשלב ענבר ווניל, עם עמידות ארוכה לשעות."}}'::jsonb),
