  ('lj-007', 'lamset-jamal', 'كريم ليلي مغذي بالكولاجين', 'عناية بالبشرة', 90, 110, 'https://picsum.photos/seed/lj007/600/700', '{"https://picsum.photos/seed/lj007/600/700"}', 'كريم ليلي كثيف بيجدد خلايا البشرة أثناء النوم ويقلل من علامات التعب.', '{}', '{}', '{"en":{"name":"Collagen Nourishing Night Cream","description":"A rich night cream that renews skin cells while you sleep and reduces signs of tiredness."},"he":{"name":"קרם לילה מזין בקולגן","description":"קרם לילה עשיר שמחדש את תאי העור בזמן השינה ומפחית סימני עייפות."}}'::jsonb),
