  ('ls-001', 'lamset-sabaya', 'طقم إكسسوارات لؤلؤ', 'إكسسوارات', 60, 75, 'https://picsum.photos/seed/ls001/600/700', '{"https://picsum.photos/seed/ls001/600/700"}', 'طقم يتكون من قلادة وأقراط بتصميم لؤلؤي أنيق يناسب السهرات.', '{"ذهبي","فضي"}', '{}', '{"en":{"name":"Pearl Accessory Set","description":"A set of an elegant pearl-design necklace and earrings, perfect for evenings."},"he":{"name":"סט אביזרי פנינים","description":"סט הכולל שרשרת ועגילים בעיצוב פנינים אלגנטי, מושלם לערבים."}}'::jsonb),
